// ── HELPER FUNCTIONS ────────────────────────────────────────

/** Alphabetical list of all provinces */
export const PROVINCES = Object.keys(LUZON_DATA).sort();

/** Alphabetical list of all cities/municipalities for a given province */
export const getCitiesForProvince = (province) => {
  if (!province || !LUZON_DATA[province]) return [];
  return Object.keys(LUZON_DATA[province]).sort();
};

/** Municipalities array for a given province+city */
export const getMunicipalitiesForCity = (province, city) => {
  if (!province || !city || !LUZON_DATA[province]?.[city]) return [];
  return [...LUZON_DATA[province][city].municipalities].sort();
};

/** Barangays array for a given province+city */
export const getBarangaysForCity = (province, city) => {
  if (!province || !city || !LUZON_DATA[province]?.[city]) return [];
  return [...LUZON_DATA[province][city].barangays].sort();
};

/** Auto-fill postal code when province + city are selected */
export const getPostalCode = (province, city) => {
  if (!province || !city || !LUZON_DATA[province]?.[city]) return "";
  return LUZON_DATA[province][city].postalCode;
};

/** Returns true if the postal code belongs to any Luzon city */
export const isLuzonPostalCode = (code) => {
  const trimmed = code.trim();
  return Object.values(LUZON_DATA).some((cities) =>
    Object.values(cities).some((c) => c.postalCode === trimmed)
  );
};

// ── ADDITIONAL HELPERS FOR PROVINCE / CITY MODE ────────────

/**
 * Province mode:
 * Get all unique municipalities across ALL cities in a province.
 * Each "city key" in the data has a municipalities[] array — flatten them all.
 */
export const getMunicipalitiesForProvince = (province) => {
  if (!province || !LUZON_DATA[province]) return [];
  const all = Object.values(LUZON_DATA[province]).flatMap((c) => c.municipalities);
  return [...new Set(all)].sort();
};

/**
 * Province mode:
 * Get barangays for a specific municipality within a province.
 * Find which city-key contains that municipality, return its barangays.
 */
export const getBarangaysForMunicipality = (province, municipality) => {
  if (!province || !municipality || !LUZON_DATA[province]) return [];
  const cityEntry = Object.values(LUZON_DATA[province]).find((c) =>
    c.municipalities.includes(municipality)
  );
  if (!cityEntry) return [];
  return [...cityEntry.barangays].sort();
};

/**
 * Province mode:
 * Get postal code for a municipality within a province.
 */
export const getPostalCodeForMunicipality = (province, municipality) => {
  if (!province || !municipality || !LUZON_DATA[province]) return "";
  const cityEntry = Object.values(LUZON_DATA[province]).find((c) =>
    c.municipalities.includes(municipality)
  );
  return cityEntry ? cityEntry.postalCode : "";
};

/**
 * City mode:
 * Flat list of ALL cities across ALL provinces (alphabetical).
 * Returns array of { province, city } objects.
 */
export const getAllCities = () => {
  const result = [];
  for (const province of Object.keys(LUZON_DATA).sort()) {
    for (const city of Object.keys(LUZON_DATA[province]).sort()) {
      result.push({ province, city });
    }
  }
  return result;
};
